// Curated classical Ayurvedic herbs. ~100 entries sourced from Charaka
// Samhita, Sushruta Samhita, Ashtanga Hridaya, and the major Nighantus
// (Dhanvantari, Madanaphala, Kaiyadeva, Bhavaprakasha, Raja Nighantu).
//
// This is NOT a complete materia medica. Classical Ayurvedic texts describe
// 600+ drugs. We have curated the most-cited ~100 used in classical
// formulations (see `source` field on each entry).
//
// IMPORTANT DISCLAIMER (also rendered on the public page):
// Information here is for educational/cultural reference only. It is NOT
// medical advice. Consult a qualified Ayurvedic practitioner before use.
// Many herbs have drug interactions and contra-indications.

export type Herb = {
  id: string                  // slug
  name: string                // English / common
  sanskrit: string            // primary Sanskrit name
  alsoKnownAs: string[]       // other Sanskrit / regional names (max 3)
  botanical: string           // botanical / family when "Combination"
  family: string
  partsUsed: string[]
  rasa: string[]              // taste per classical Ayurveda
  guna: string[]              // property
  virya: 'Ushna' | 'Sheeta' | 'Anushna'  // potency
  vipaka: string              // post-digestive effect
  dosha: string               // which doshas it balances / aggravates
  classicalUses: string[]     // 3-6 short classical use cases
  evidence: 'Strong' | 'Moderate' | 'Traditional' | 'Preliminary'
  evidenceNote: string        // one-line, what modern research says
  formulations: string[]      // classical formulations it appears in
  source: string              // classical text reference
  precautions: string
  emoji: string               // visual icon
  image: string               // Wikimedia / Unsplash photo URL
  category: string            // therapeutic category for filtering
}

