export function searchHerbs(query: string): Herb[] {
  const q = query.toLowerCase().trim();
  if (!q) return H;
  return H.filter(h =>
    h.name.toLowerCase().includes(q) ||
    h.sanskrit.toLowerCase().includes(q) ||
    h.alsoKnownAs.some(a => a.toLowerCase().includes(q)) ||
    h.botanical.toLowerCase().includes(q) ||
    h.classicalUses.some(u => u.toLowerCase().includes(q)) ||
    h.category.toLowerCase().includes(q)
  );
}

export function getHerbsByCategory(category: string): Herb[] {
  return H.filter(h => h.category === category);
}

export function getHerbById(id: string): Herb | undefined {
  return H.find(h => h.id === id);
}

